// PATCH(namecheap-query-auth-status): regression coverage for Namecheap query-param auth detection.
func TestAuthStatusUsesNamecheapQueryCredentials(t *testing.T) {
	t.Setenv("NAMECHEAP_USERNAME", "demo-user")
	t.Setenv("NAMECHEAP_API_KEY", "demo-key")
	t.Setenv("NAMECHEAP_CONFIG", t.TempDir()+"/config.toml")

	flags := &rootFlags{asJSON: true}
	cmd := newAuthStatusCmd(flags)
	var out bytes.Buffer
	cmd.SetOut(&out)

	if err := cmd.Execute(); err != nil {
		t.Fatalf("auth status with Namecheap query credentials returned error: %v", err)
	}

	var got map[string]any
	if err := json.Unmarshal(out.Bytes(), &got); err != nil {
		t.Fatalf("auth status JSON did not parse: %v\n%s", err, out.String())
	}
	if got["authenticated"] != true {
		t.Fatalf("authenticated = %v, want true; output=%s", got["authenticated"], out.String())
	}
}

// PATCH(namecheap-api-key-env): regression coverage for auth guidance using the real env var.
func TestAuthStatusHintUsesNamecheapAPIKeyEnv(t *testing.T) {
	t.Setenv("NAMECHEAP_USERNAME", "")
	t.Setenv("NAMECHEAP_API_KEY", "")
	t.Setenv("NAMECHEAP_CONFIG", t.TempDir()+"/config.toml")

	flags := &rootFlags{}
	cmd := newAuthStatusCmd(flags)
	var out bytes.Buffer
	cmd.SetOut(&out)

	if err := cmd.Execute(); err == nil {
		t.Fatal("auth status without credentials should return an auth error")
	}

	text := out.String()
	if !strings.Contains(text, "NAMECHEAP_API_KEY=") {
		t.Fatalf("auth status hint should mention NAMECHEAP_API_KEY, got: %s", text)
	}
	if strings.Contains(text, "NAMECHEAP_API_KEY_QUERY") {
		t.Fatalf("auth status hint should not mention stale NAMECHEAP_API_KEY_QUERY, got: %s", text)
	}
}

// PATCH(namecheap-set-token-api-key): regression coverage for persisting Namecheap API keys to api_key.
func TestAuthSetTokenPersistsNamecheapAPIKey(t *testing.T) {
	configPath := filepath.Join(t.TempDir(), "config.toml")
	t.Setenv("NAMECHEAP_CONFIG", configPath)
	t.Setenv("NAMECHEAP_USERNAME", "demo-user")
	t.Setenv("NAMECHEAP_API_KEY", "")

	flags := &rootFlags{}
	cmd := newAuthSetTokenCmd(flags)
	cmd.SetArgs([]string{"persisted-key"})
	var out bytes.Buffer
	cmd.SetOut(&out)

	if err := cmd.Execute(); err != nil {
		t.Fatalf("auth set-token returned error: %v", err)
	}

	// Clear env so config.Load proves the key came from TOML, not process state.
	t.Setenv("NAMECHEAP_USERNAME", "")
	loaded, err := config.Load(configPath)
	if err != nil {
		t.Fatalf("loading config after set-token: %v", err)
	}
	if loaded.APIKey != "persisted-key" {
		data, _ := os.ReadFile(configPath)
		t.Fatalf("APIKey = %q, want persisted-key; config=%s", loaded.APIKey, string(data))
	}
	if loaded.AccessToken != "" {
		t.Fatalf("AccessToken = %q, want empty because Namecheap uses api_key", loaded.AccessToken)
	}
}
